import{_ as a,o as n,c as i,ag as p}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"第 17 章 权限与确认系统","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/17-permissions.md","filePath":"chapters/17-permissions.md"}'),e={name:"chapters/17-permissions.md"};function l(t,s,o,h,r,c){return n(),i("div",null,[...s[0]||(s[0]=[p(`<h1 id="第-17-章-权限与确认系统" tabindex="-1">第 17 章 权限与确认系统 <a class="header-anchor" href="#第-17-章-权限与确认系统" aria-label="Permalink to &quot;第 17 章 权限与确认系统&quot;">​</a></h1><blockquote><p>&quot;Security is always excessive until it&#39;s not enough.&quot; —— Robbie Sinclair</p></blockquote><p>一个能读写文件、执行 Shell 命令、发起网络请求的 AI 工具，如果缺乏有效的权限控制，就等于给用户的系统装了一扇没有锁的门。Claude Code 的权限系统是它安全模型的核心——每一次工具调用都要经过权限检查，任何可能产生副作用的操作都需要获得明确授权。本章将深入剖析这套权限体系的分层设计、规则匹配逻辑和用户确认流程。</p><h2 id="_17-1-权限系统的文件结构" tabindex="-1">17.1 权限系统的文件结构 <a class="header-anchor" href="#_17-1-权限系统的文件结构" aria-label="Permalink to &quot;17.1 权限系统的文件结构&quot;">​</a></h2><p>权限相关的代码集中在 <code>src/utils/permissions/</code> 目录下，每个文件负责一个清晰的职责：</p><ul><li><strong>permissions.ts</strong> —— 主入口，包含通用权限检查逻辑</li><li><strong>PermissionMode.ts</strong> —— 定义六种权限模式</li><li><strong>PermissionResult.ts</strong> —— 决策结果类型（允许、拒绝、需要询问）</li><li><strong>PermissionRule.ts</strong> —— 规则格式定义与匹配逻辑</li><li><strong>filesystem.ts</strong> —— 文件操作的专项权限检查</li><li><strong>shellRuleMatching.ts</strong> —— Bash 命令的模式匹配</li><li><strong>denialTracking.ts</strong> —— 记录被拒绝的操作</li><li><strong>permissionRuleParser.ts</strong> —— 解析 <code>.clauderc</code> 等配置文件中的规则</li></ul><h2 id="_17-2-六种权限模式" tabindex="-1">17.2 六种权限模式 <a class="header-anchor" href="#_17-2-六种权限模式" aria-label="Permalink to &quot;17.2 六种权限模式&quot;">​</a></h2><p><code>PermissionMode.ts</code> 定义了六种运行模式，从最严格到最宽松排列：</p><p><strong>plan 模式</strong> —— 只读模式。所有写操作（文件编辑、Shell 命令、网络请求）一律被拒绝，模型只能读取文件和分析代码。适用于&quot;先看看它会怎么做&quot;的场景。</p><p><strong>dontAsk 模式</strong> —— 静默拒绝。任何需要用户确认的操作都会被自动拒绝，不弹出确认提示。适用于自动化管道中不希望被交互式提示阻塞的场景。</p><p><strong>default 模式</strong> —— 标准模式。读操作自动放行，写操作弹出确认提示。这是绝大多数用户日常使用的模式。</p><p><strong>acceptEdits 模式</strong> —— 自动接受文件编辑，但其他写操作（如 Shell 命令）仍然需要确认。适用于信任模型的编辑能力、但对命令执行保持谨慎的场景。</p><p><strong>bypassPermissions 模式</strong> —— 跳过所有权限检查，一切操作自动放行。这是一个危险模式，仅在用户明确知晓风险的前提下启用。</p><p><strong>auto 模式</strong> —— 基于分类器（classifier）自动判断。这是一个实验性模式，仅在启用了 <code>TRANSCRIPT_CLASSIFIER</code> 特性开关时可用：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/utils/permissions/permissions.ts:59-64</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> classifierDecisionModule</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> feature</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;TRANSCRIPT_CLASSIFIER&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  ?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">require</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./classifierDecision.js&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> typeof</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./classifierDecision.js&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  :</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span></span></code></pre></div><p>auto 模式使用一个独立的分类模型来评估每次操作的风险等级，然后自动做出允许或拒绝的决策。这种方式的目标是在安全性和便利性之间找到更优的平衡点——高风险操作仍然会被拦截，低风险操作则无需用户手动确认。</p><h2 id="_17-3-权限规则与匹配" tabindex="-1">17.3 权限规则与匹配 <a class="header-anchor" href="#_17-3-权限规则与匹配" aria-label="Permalink to &quot;17.3 权限规则与匹配&quot;">​</a></h2><p>除了模式级别的控制，用户还可以定义细粒度的权限规则。规则分为三类：<code>alwaysAllow</code>（始终允许）、<code>alwaysDeny</code>（始终拒绝）和 <code>alwaysAsk</code>（始终询问）。这些规则通过 <code>ToolPermissionContext</code> 传递给权限检查逻辑：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/tools/Tool.ts:123-138</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ToolPermissionContext</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DeepImmutable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;{</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> PermissionMode</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  additionalWorkingDirectories</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AdditionalWorkingDirectory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  alwaysAllowRules</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ToolPermissionRulesBySource</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  alwaysDenyRules</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ToolPermissionRulesBySource</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  alwaysAskRules</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ToolPermissionRulesBySource</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  isBypassPermissionsModeAvailable</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}&gt;</span></span></code></pre></div><p><code>ToolPermissionRulesBySource</code> 的 &quot;BySource&quot; 后缀意味着规则带有来源信息——是来自全局配置、项目配置还是 MDM 企业策略。这个来源信息在规则冲突时用于确定优先级。</p><p>规则匹配的过程因工具类型而异。文件操作的规则匹配在 <code>filesystem.ts</code> 中实现，需要处理路径通配符、目录递归匹配等文件系统特有的逻辑。Shell 命令的规则匹配在 <code>shellRuleMatching.ts</code> 中实现，需要解析命令字符串、识别管道和重定向，确保用户编写的 <code>allow: &quot;git *&quot;</code> 规则不会意外匹配到 <code>git push --force</code>（如果用户不希望的话）。</p><p><code>permissionRuleParser.ts</code> 负责从 <code>.clauderc</code> 和其他配置文件中解析规则定义。规则格式需要在表达力和简洁性之间取得平衡——太简单则无法覆盖复杂场景，太复杂则用户不愿意写。</p><h2 id="_17-4-权限检查的完整流程" tabindex="-1">17.4 权限检查的完整流程 <a class="header-anchor" href="#_17-4-权限检查的完整流程" aria-label="Permalink to &quot;17.4 权限检查的完整流程&quot;">​</a></h2><p>当一个工具准备执行时，权限检查经历多个层次的过滤：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>工具请求执行</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>validateInput() -- 输入合法性校验</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 不合法 --&gt; 直接拒绝，返回错误信息</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 合法 --&gt; 继续</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        v</span></span>
<span class="line"><span>  checkPermissions() -- 工具自身的权限逻辑</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        +-- &#39;allow&#39; --&gt; 直接放行，执行工具</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        +-- &#39;deny&#39; --&gt; 直接拒绝</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        +-- &#39;passthrough&#39; --&gt; 进入通用权限检查</span></span>
<span class="line"><span>              |</span></span>
<span class="line"><span>              v</span></span>
<span class="line"><span>        匹配 alwaysAllow 规则</span></span>
<span class="line"><span>              |</span></span>
<span class="line"><span>              +-- 命中 --&gt; 放行</span></span>
<span class="line"><span>              |</span></span>
<span class="line"><span>              +-- 未命中 --&gt; 继续</span></span>
<span class="line"><span>                    |</span></span>
<span class="line"><span>                    v</span></span>
<span class="line"><span>              匹配 alwaysDeny 规则</span></span>
<span class="line"><span>                    |</span></span>
<span class="line"><span>                    +-- 命中 --&gt; 拒绝</span></span>
<span class="line"><span>                    |</span></span>
<span class="line"><span>                    +-- 未命中 --&gt; 继续</span></span>
<span class="line"><span>                          |</span></span>
<span class="line"><span>                          v</span></span>
<span class="line"><span>                    检查 PermissionMode</span></span>
<span class="line"><span>                          |</span></span>
<span class="line"><span>                          +-- bypassPermissions --&gt; 放行</span></span>
<span class="line"><span>                          +-- dontAsk --&gt; 拒绝</span></span>
<span class="line"><span>                          +-- plan（且是写操作）--&gt; 拒绝</span></span>
<span class="line"><span>                          +-- auto --&gt; 调用分类器决策</span></span>
<span class="line"><span>                          +-- default/acceptEdits --&gt; 弹出确认提示</span></span>
<span class="line"><span>                                |</span></span>
<span class="line"><span>                                v</span></span>
<span class="line"><span>                          用户确认</span></span>
<span class="line"><span>                                |</span></span>
<span class="line"><span>                                +-- 允许 --&gt; 执行</span></span>
<span class="line"><span>                                +-- 允许并记住 --&gt; 添加到 alwaysAllow，执行</span></span>
<span class="line"><span>                                +-- 拒绝 --&gt; 记录到 denialTracking</span></span></code></pre></div><p>这个流程的设计体现了&quot;快速路径优先&quot;的原则。最常见的情况——用户已经配置了 alwaysAllow 规则的操作——在流程的最前端就被放行，不需要经过后续的模式检查和用户确认。只有真正需要决策的操作才会走到流程末端。</p><h2 id="_17-5-工具级权限钩子" tabindex="-1">17.5 工具级权限钩子 <a class="header-anchor" href="#_17-5-工具级权限钩子" aria-label="Permalink to &quot;17.5 工具级权限钩子&quot;">​</a></h2><p>每个工具都可以实现自己的 <code>checkPermissions</code> 方法，在通用权限检查之前执行自定义逻辑。这个钩子返回三种结果之一：</p><ul><li><code>allow</code> —— 工具自行判定操作安全，跳过通用检查</li><li><code>deny</code> —— 工具自行判定操作危险，直接拒绝</li><li><code>passthrough</code> —— 工具不做判定，交给通用权限逻辑处理</li></ul><p>举例来说，Read 工具（读取文件）在大多数模式下直接返回 <code>allow</code>，因为读取操作通常不需要确认。而 Bash 工具则需要分析命令内容——如果命令是 <code>ls</code> 或 <code>cat</code> 之类的纯读取操作，可以提前放行；如果是 <code>rm</code> 或 <code>chmod</code>，则需要通用权限流程来决策。</p><h2 id="_17-6-拒绝追踪" tabindex="-1">17.6 拒绝追踪 <a class="header-anchor" href="#_17-6-拒绝追踪" aria-label="Permalink to &quot;17.6 拒绝追踪&quot;">​</a></h2><p><code>denialTracking.ts</code> 记录了所有被用户拒绝的操作。这份记录有两个用途。第一，避免重复打扰——如果用户刚刚拒绝了某个操作，模型在短时间内再次尝试同样的操作时，系统可以直接拒绝而不再弹出确认框。第二，为模型提供反馈——拒绝记录会被包含在工具执行结果中，告诉模型&quot;用户不希望执行这个操作&quot;，帮助模型调整后续策略。</p><p>这个机制解决了一个实际问题：没有拒绝追踪时，模型可能会反复尝试被用户拒绝的操作，每次都弹出确认框，造成糟糕的用户体验。有了追踪之后，一次拒绝就足以让模型理解用户意图。</p><h2 id="_17-7-文件系统的特殊处理" tabindex="-1">17.7 文件系统的特殊处理 <a class="header-anchor" href="#_17-7-文件系统的特殊处理" aria-label="Permalink to &quot;17.7 文件系统的特殊处理&quot;">​</a></h2><p>文件操作的权限检查比其他工具更为复杂，因为需要考虑路径的层级关系。<code>filesystem.ts</code> 处理了以下问题：</p><p>工作目录约束——默认情况下，文件操作只允许在项目的工作目录及其子目录中执行。<code>additionalWorkingDirectories</code> 配置允许用户扩展可操作的目录范围。</p><p>路径规范化——用户可能输入相对路径、包含 <code>..</code> 的路径、符号链接路径，这些都需要解析为绝对路径后再与规则匹配，防止通过路径变体绕过权限限制。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>Claude Code 的权限系统采用了多层防御策略。六种权限模式从全局层面控制操作许可范围，三类规则（alwaysAllow、alwaysDeny、alwaysAsk）提供细粒度的操作级控制，每个工具的 <code>checkPermissions</code> 钩子处理工具特有的安全逻辑。权限检查流程按&quot;快速路径优先&quot;原则设计——最常见的操作在最少的步骤内完成决策。拒绝追踪机制避免模型重复尝试被用户否决的操作。整套体系的核心设计意图很明确：在确保安全的前提下，尽可能减少对用户工作流的打断。</p>`,39)])])}const g=a(e,[["render",l]]);export{k as __pageData,g as default};
